// Load file(s) into a BigQuery table.
// The adaptor batches rows from disk; for one-off row inserts you typically
// write the row(s) to a local file first and point `load` at it.
load(
  // 1) Path to the local directory containing files to load.
  './tmp/files',
  // 2) GCP project id.
  $.configuration.projectId,
  // 3) Dataset id.
  'my_dataset',
  // 4) Target table id.
  'my_table',
  {
    // Column types (BQ schema string).
    schema: 'name:STRING,email:STRING,amount:NUMERIC',
    // Append rather than replace.
    writeDisposition: 'WRITE_APPEND',
    // Skip header row(s) if loading CSV.
    skipLeadingRows: 1,
    createDisposition: 'CREATE_IF_NEEDED',
  }
);
